mepc_setup:       
                  la x6, init
                  csrw 0x341, x6

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_user_mode:   
                  li x6, 0x50000f2
                  csrw 0x300, x6 # MSTATUS
                  li x6, 0x53ac7fbb
                  csrw 0x304, x6 # MIE
                  li x20, 0x8ffffffc
                  li x20, 0x8ffffffc
                  li x20, 0x8ffffffc
                  li x6, 0x300
                  slli x6, x6, 8
                  addi x6, x6, 0x3
                  sw x6, 0(x20)
                  csrr x6, 0x300
                  sw x6, 0(x20)
                  li x20, 0x8ffffffc
                  li x6, 0x304
                  slli x6, x6, 8
                  addi x6, x6, 0x3
                  sw x6, 0(x20)
                  csrr x6, 0x304
                  sw x6, 0(x20)
                  mret
init:             
                  li x0, 0xff8b810e
                  li x1, 0x7327cba0
                  li x2, 0xf5e39895
                  li x3, 0x0
